// Formater les détails du service
const response = $input.item.json.result || $input.item.json;
const data = response.data || response;

if (!data || typeof data !== 'object' || !data.SERVER_NAME) {
  return {
    json: {
      success: false,
      message: "Service non trouvé.",
      service: null
    }
  };
}

// Extraire les valeurs
const serviceName = data.SERVER_NAME?.value || 'Unknown';
const isDraft = data.IS_DRAFT?.value === 'yes';
const method = data.SERVER_NAME?.method || 'N/A';
const status = isDraft ? '📝 Brouillon' : '✅ En ligne';

let formattedText = `Service **${serviceName}** - ${status}\n\n`;
formattedText += `• Méthode: ${method}\n`;

// Variables importantes à afficher
const importantVars = [
  'USE_MODSECURITY',
  'USE_MODSECURITY_CRS',
  'USE_ANTIBOT',
  'USE_LIMIT_REQ',
  'USE_BAD_BEHAVIOR',
  'AUTO_LETS_ENCRYPT',
  'REVERSE_PROXY_URL',
  'USE_REVERSE_PROXY'
];

// Filtrer pour ne garder que les variables non-globales (spécifiques au service)
const serviceSpecificVars = {};
Object.keys(data).forEach(key => {
  if (data[key]?.global === false || importantVars.includes(key)) {
    serviceSpecificVars[key] = data[key];
  }
});

formattedText += '\n**Configuration:**\n';
importantVars.forEach(varName => {
  if (serviceSpecificVars[varName]?.value) {
    const val = serviceSpecificVars[varName].value;
    const isGlobal = serviceSpecificVars[varName].global ? ' (global)' : '';
    formattedText += `• ${varName}: ${val}${isGlobal}\n`;
  }
});

const otherServiceVars = Object.keys(serviceSpecificVars).filter(k => 
  !importantVars.includes(k) && k !== 'SERVER_NAME' && k !== 'IS_DRAFT'
).length;

if (otherServiceVars > 0) {
  formattedText += `\n(+ ${otherServiceVars} autre(s) variable(s) spécifique(s))\n`;
}

return {
  json: {
    success: true,
    message: formattedText,
    service: serviceSpecificVars  // Ne retourner que les vars spécifiques au service
  }
};
